arguments.prompt:
You are working in /tmp/sv-d940b80ca58842a59f51b7c365ac87b1/ShipmentTracker. This is a Blazor Web App solution with two projects:
- ShipmentTracker (server project) - has Data/, Components/, Program.cs
- ShipmentTracker.Client (client/WebAssembly project) - has Pages/, Layout/

The app uses Interactive WebAssembly render mode with Individual auth (ASP.NET Identity with SQLite). The template already has authentication working.

I need you to build a logistics shipment tracking app with these requirements:
1. Dispatchers view a list of shipments with status and destination
2. Customers check their shipment status and estimated delivery
3. Role-based authorization: "Dispatcher" and "Customer" roles
4. API endpoints on the server for shipment data
5. Client pages that call the API

Here's what to do:

## 1. Create shared models

Create file: ShipmentTracker.Client/Models/ShipmentDto.cs
```csharp
namespace ShipmentTracker.Client.Models;

public class ShipmentDto
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public string Status { get; set; } = string.Empty;
    public DateTime ShippedDate { get; set; }
    public DateTime EstimatedDelivery { get; set; }
    public string? CustomerEmail { get; set; }
}
```

## 2. Create the server-side Shipment entity and seed data

Create file: ShipmentTracker/Data/Shipment.cs
```csharp
using Microsoft.AspNetCore.Identity;

namespace ShipmentTracker.Data;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public string Status { get; set; } = string.Empty; // Pending, InTransit, Delivered, Delayed
    public DateTime ShippedDate { get; set; }
    public DateTime EstimatedDelivery { get; set; }
    public string? CustomerId { get; set; }
    public ApplicationUser? Customer { get; set; }
}
```

## 3. Update ApplicationDbContext

Edit ShipmentTracker/Data/ApplicationDbContext.cs to add:
- A DbSet<Shipment> Shipments property
- Override OnModelCreating to configure the Shipment entity and seed sample data

The file currently looks like this (probably):
```csharp
using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;

namespace ShipmentTracker.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
}
```

Replace it with:
```csharp
using Microsoft.AspNetCore.Identity;
using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;

namespace ShipmentTracker.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Shipment> Shipments => Set<Shipment>();

    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        builder.Entity<Shipment>(e =>
        {
            e.HasIndex(s => s.TrackingNumber).IsUnique();
            e.HasOne(s => s.Customer)
                .WithMany()
                .HasForeignKey(s => s.CustomerId)
                .OnDelete(DeleteBehavior.SetNull);
        });
    }
}
```

## 4. Create API endpoints

Create file: ShipmentTracker/Endpoints/ShipmentEndpoints.cs
```csharp
using System.Security.Claims;
using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // Dispatchers: get all shipments
        group.MapGet("/", async (ApplicationDbContext db, ClaimsPrincipal user) =>
        {
            if (!user.IsInRole("Dispatcher"))
                return Results.Forbid();

            var shipments = await db.Shipments
                .Include(s => s.Customer)
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status,
                    ShippedDate = s.ShippedDate,
                    EstimatedDelivery = s.EstimatedDelivery,
                    CustomerEmail = s.Customer != null ? s.Customer.Email : null
                })
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // Dispatchers: update shipment status
        group.MapPut("/{id:int}/status", async (int id, StatusUpdateDto update, ApplicationDbContext db, ClaimsPrincipal user) =>
        {
            if (!user.IsInRole("Dispatcher"))
                return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null)
                return Results.NotFound();

            shipment.Status = update.Status;
            await db.SaveChangesAsync();
            return Results.NoContent();
        });

        // Customers: get their own shipments
        group.MapGet("/my", async (ApplicationDbContext db, ClaimsPrincipal user) =>
        {
            var userId = user.FindFirstValue(ClaimTypes.NameIdentifier);

            var shipments = await db.Shipments
                .Where(s => s.CustomerId == userId)
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status,
                    ShippedDate = s.ShippedDate,
                    EstimatedDelivery = s.EstimatedDelivery
                })
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // Customers: track a specific shipment by tracking number
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .Where(s => s.TrackingNumber == trackingNumber)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status,
                    ShippedDate = s.ShippedDate,
                    EstimatedDelivery = s.EstimatedDelivery
                })
                .FirstOrDefaultAsync();

            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });
    }
}

public record StatusUpdateDto(string Status);
```

## 5. Create data seeder

Create file: ShipmentTracker/Data/SeedData.cs
```csharp
using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;

namespace ShipmentTracker.Data;

public static class SeedData
{
    public static async Task InitializeAsync(IServiceProvider services)
    {
        using var scope = services.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
        var userManager = scope.ServiceProvider.GetRequiredService<UserManager<ApplicationUser>>();
        var roleManager = scope.ServiceProvider.GetRequiredService<RoleManager<IdentityRole>>();

        await db.Database.MigrateAsync();

        // Create roles
        string[] roles = ["Dispatcher", "Customer"];
        foreach (var role in roles)
        {
            if (!await roleManager.RoleExistsAsync(role))
                await roleManager.CreateAsync(new IdentityRole(role));
        }

        // Create dispatcher user
        var dispatcher = await userManager.FindByEmailAsync("dispatcher@shiptrack.com");
        if (dispatcher is null)
        {
            dispatcher = new ApplicationUser
            {
                UserName = "dispatcher@shiptrack.com",
                Email = "dispatcher@shiptrack.com",
                EmailConfirmed = true
            };
            await userManager.CreateAsync(dispatcher, "Dispatch1!");
            await userManager.AddToRoleAsync(dispatcher, "Dispatcher");
        }

        // Create customer user
        var customer = await userManager.FindByEmailAsync("customer@example.com");
        if (customer is null)
        {
            customer = new ApplicationUser
            {
                UserName = "customer@example.com",
                Email = "customer@example.com",
                EmailConfirmed = true
            };
            await userManager.CreateAsync(customer, "Customer1!");
            await userManager.AddToRoleAsync(customer, "Customer");
        }

        // Seed shipments if none exist
        if (!await db.Shipments.AnyAsync())
        {
            var shipments = new List<Shipment>
            {
                new()
