    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private string? errorMessage;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrEmpty(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        try
        {
            shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>(
                Nav.ToAbsoluteUri("/api/shipments"));
        }
        catch (HttpRequestException ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, string newStatus)
    {
        try
        {
            var response = await Http.PutAsJsonAsync(
                Nav.ToAbsoluteUri($"/api/shipments/{shipment.Id}/status"),
                new { Status = newStatus });
            if (response.IsSuccessStatusCode)
            {
                shipment.Status = newStatus;
            }
        }
        catch
        {
            errorMessage = "Failed to update status.";
        }
    }

    private string GetStatusBadge(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "InTransit" => "bg-primary",
        "Delivered" => "bg-success",
        "Delayed" => "bg-warning text-dark",
        _ => "bg-info"
    };
}
