```csharp
using System.Security.Claims;
using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // Dispatchers: get all shipments
        group.MapGet("/", async (ApplicationDbContext db, ClaimsPrincipal user) =>
        {
            if (!user.IsInRole("Dispatcher"))
                return Results.Forbid();

            var shipments = await db.Shipments
                .Include(s => s.Customer)
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status,
                    ShippedDate = s.ShippedDate,
                    EstimatedDelivery = s.EstimatedDelivery,
                    CustomerEmail = s.Customer != null ? s.Customer.Email : null
                })
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // Dispatchers: update shipment status
        group.MapPut("/{id:int}/status", async (int id, StatusUpdateDto update, ApplicationDbContext db, ClaimsPrincipal user) =>
        {
            if (!user.IsInRole("Dispatcher"))
                return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null)
                return Results.NotFound();

            shipment.Status = update.Status;
            await db.SaveChangesAsync();
            return Results.NoContent();
        });

        // Customers: get their own shipments
        group.MapGet("/my", async (ApplicationDbContext db, ClaimsPrincipal user) =>
        {
            var userId = user.FindFirstValue(ClaimTypes.NameIdentifier);

            var shipments = await db.Shipments
                .Where(s => s.CustomerId == userId)
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status,
                    ShippedDate = s.ShippedDate,
                    EstimatedDelivery = s.EstimatedDelivery
                })
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // Customers: track a specific shipment by tracking number
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .Where(s => s.TrackingNumber == trackingNumber)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status,
                    ShippedDate = s.ShippedDate,
                    EstimatedDelivery = s.EstimatedDelivery
                })
                .FirstOrDefaultAsync();

            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });
    }
}

public record StatusUpdateDto(string Status);
```

