@page "/dispatch"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize(Roles = "Dispatcher")]
@inject HttpClient Http
@inject NavigationManager Nav

<PageTitle>Dispatch Dashboard</PageTitle>

<h1>📦 Dispatch Dashboard</h1>

@if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Filter by destination or tracking #..."
               @bind="filterText" @bind:event="oninput" />
    </div>

    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>ETA</th>
                <th>Customer</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in FilteredShipments)
            {
                <tr>
                    <td><strong>@s.TrackingNumber</strong></td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td><span class="badge @GetStatusBadge(s.Status)">@s.Status</span></td>
                    <td>@s.ShippedDate.ToString("MMM dd, yyyy")</td>
                    <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                    <td>@(s.CustomerEmail ?? "—")</td>
                    <td>
                        <select class="form-select form-select-sm" value="@s.Status"
                                @onchange="e => UpdateStatus(s, e.Value?.ToString()!)">
                            <option value="Pending">Pending</option>
                            <option value="InTransit">In Transit</option>
                            <option value="Delivered">Delivered</option>
                            <option value="Delayed">Delayed</option>
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>

    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private string? errorMessage;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrEmpty(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        try
        {
            shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>(
                Nav.ToAbsoluteUri("/api/shipments"));
        }
        catch (HttpRequestException ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, string newStatus)
    {
        try
        {
            var response = await Http.PutAsJsonAsync(
                Nav.ToAbsoluteUri($"/api/shipments/{shipment.Id}/status"),
                new { Status = newStatus });
            if (response.IsSuccessStatusCode)
            {
                shipment.Status = newStatus;
            }
        }
        catch
        {
            errorMessage = "Failed to update status.";
        }
    }

    private string GetStatusBadge(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "InTransit" => "bg-primary",
        "Delivered" => "bg-success",
        "Delayed" => "bg-warning text-dark",
        _ => "bg-info"
    };
}

