@attribute [Authorize(Roles = "Customer")]
@inject HttpClient Http
@inject NavigationManager Nav

<PageTitle>My Shipments</PageTitle>

<h1>📬 My Shipments</h1>

@if (shipments is null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <p>No shipments found for your account.</p>
}
else
{
    <div class="row">
        @foreach (var s in shipments)
        {
            <div class="col-md-6 col-lg-4 mb-3">
                <div class="card h-100">
                    <div class="card-header d-flex justify-content-between">
                        <strong>@s.TrackingNumber</strong>
                        <span class="badge @GetStatusBadge(s.Status)">@s.Status</span>
                    </div>
                    <div class="card-body">
                        <p><strong>From:</strong> @s.Origin</p>
                        <p><strong>To:</strong> @s.Destination</p>
                        <p><strong>Shipped:</strong> @s.ShippedDate.ToString("MMM dd, yyyy")</p>
                        <p class="mb-0"><strong>Estimated Delivery:</strong>
                            <span class="@(s.Status == "Delayed" ? "text-warning fw-bold" : "")">
                                @s.EstimatedDelivery.ToString("MMM dd, yyyy")
                            </span>
                        </p>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<ShipmentDto>? shipments;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>(
                Nav.ToAbsoluteUri("/api/shipments/my"));
        }
        catch
        {
            shipments = new();
        }
    }

    private string GetStatusBadge(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "InTransit" => "bg-primary",
        "Delivered" => "bg-success",
        "Delayed" => "bg-warning text-dark",
        _ => "bg-info"
    };
}

