@page "/track"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize]
@inject HttpClient Http
@inject NavigationManager Nav

<PageTitle>Track Shipment</PageTitle>

<h1>🔍 Track a Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g. TRK-001-2026)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="Search" disabled="@searching">
                @(searching ? "Searching..." : "Track")
            </button>
        </div>
    </div>
</div>

@if (notFound)
{
    <div class="alert alert-warning">No shipment found with that tracking number.</div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <h4 class="mb-0">@shipment.TrackingNumber</h4>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>Origin:</strong> @shipment.Origin</p>
                    <p><strong>Destination:</strong> @shipment.Destination</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Status:</strong> <span class="badge @GetStatusBadge(shipment.Status) fs-6">@shipment.Status</span></p>
                    <p><strong>Shipped:</strong> @shipment.ShippedDate.ToString("MMMM dd, yyyy")</p>
                    <p><strong>Estimated Delivery:</strong> @shipment.EstimatedDelivery.ToString("MMMM dd, yyyy")</p>
                </div>
            </div>

            @if (shipment.Status == "Delivered")
            {
                <div class="alert alert-success mt-3 mb-0">✅ This shipment has been delivered!</div>
            }
            else if (shipment.Status == "Delayed")
            {
                <div class="alert alert-warning mt-3 mb-0">⚠️ This shipment is delayed. Estimated delivery date may change.</div>
            }
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private ShipmentDto? shipment;
    private bool notFound;
    private bool searching;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await Search();
    }

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        searching = true;
        notFound = false;
        shipment = null;

        try
        {
            var response = await Http.GetAsync(
                Nav.ToAbsoluteUri($"/api/shipments/track/{Uri.EscapeDataString(trackingNumber.Trim())}"));
            if (response.IsSuccessStatusCode)
            {
                shipment = await response.Content.ReadFromJsonAsync<ShipmentDto>();
            }
            else
            {
                notFound = true;
            }
        }
        catch
        {
            notFound = true;
        }
        finally
        {
            searching = false;
        }
    }

    private string GetStatusBadge(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "InTransit" => "bg-primary",
        "Delivered" => "bg-success",
        "Delayed" => "bg-warning text-dark",
        _ => "bg-info"
    };
}

